from typing import Callable
import logging

logger = logging.getLogger(__name__)

TestFn = Callable[[], tuple[TestOutcome, str, list[Evidence]]]

class ControlTest:
    """Wraps a test function with metadata. Register via @ControlTestRegistry.register."""
    def __init__(self, control_id: str, test_id: str, fn: TestFn,
                 frequency: str = "daily"):
        self.control_id = control_id
        self.test_id    = test_id
        self.fn         = fn
        self.frequency  = frequency

    def run(self) -> TestResult:
        try:
            outcome, detail, evidence = self.fn()
        except Exception as exc:
            logger.exception("Test %s raised", self.test_id)
            outcome  = TestOutcome.EXCEPTION
            detail   = str(exc)
            evidence = []
        return TestResult(
            control_id=self.control_id,
            test_id=self.test_id,
            outcome=outcome,
            detail=detail,
            evidence=evidence,
        )

class ControlTestRegistry:
    _tests: dict[str, ControlTest] = {}

    @classmethod
    def register(cls, control_id: str, test_id: str, frequency: str = "daily"):
        def decorator(fn: TestFn) -> TestFn:
            cls._tests[test_id] = ControlTest(control_id, test_id, fn, frequency)
            return fn
        return decorator

    @classmethod
    def run_all(cls, control_filter: str | None = None) -> list[TestResult]:
        results = []
        for test in cls._tests.values():
            if control_filter and test.control_id != control_filter:
                continue
            results.append(test.run())
        return results

def on_test_failure(result: TestResult, risk_register: RiskRegister) -> None:
    """Recalculate residual risk for any risk entry whose control just failed."""
    for entry in risk_register.entries:
        for ctrl in entry.controls:
            if ctrl.control_id == result.control_id:
                # Temporarily set effectiveness to 0 for failed control
                original = ctrl.effectiveness
                ctrl.effectiveness = 0.0
                new_residual = entry.compute_residual_score()
                ctrl.effectiveness = original   # restore for next cycle

                if new_residual > entry.residual_risk_score:
                    entry.residual_risk_score = new_residual
                    notify_risk_owner(entry, reason=f"Control {result.control_id} test FAILED")
                break
